@bp.route('/contact', methods=['GET', 'POST'])
def contact():
    form = ContactForm()
    if form.validate_on_submit():
        message = ContactMessage(
            name=form.name.data.strip(),
            email=form.email.data.strip(),
            phone=(form.phone.data or '').strip(),
            message=form.message.data.strip())
        db.session.add(message)
        db.session.commit()
        flash('留言已提交，我们会尽快联系您。', 'success')
        return redirect(url_for('main.contact'))
    return render_template('main/contact.html', form=form)

@bp.route('/login', methods=['GET', 'POST'])
def login():
    if current_user.is_authenticated:
        return redirect(url_for('admin.dashboard'))
    form = LoginForm()
    if form.validate_on_submit():
        user = User.query.filter_by(
            username=form.username.data.strip()).first()
        if user and user.status \
                and user.check_password(form.password.data):
            login_user(user)
            user.last_login_at = utcnow_naive()
            db.session.commit()
            flash('登录成功。', 'success')
            next_url = request.args.get('next') \
                or url_for('admin.dashboard')
            return redirect(next_url)
        flash('用户名或密码错误。', 'danger')
    return render_template('auth/login.html', form=form)

@bp.route('/')
@login_required
@permission_required('dashboard.view')
def dashboard():
    stats = {
        'article_count': Article.query.count(),
        'published_count': Article.query.filter_by(
            status='published').count(),
        'category_count': Category.query.count(),
        'message_count': ContactMessage.query.count(),
        'user_count': User.query.count(),
    }
    latest_articles = Article.query.order_by(
        Article.created_at.desc()).limit(5).all()
    latest_messages = ContactMessage.query.order_by(
        ContactMessage.created_at.desc()).limit(5).all()
    return render_template('admin/dashboard.html',
        stats=stats, latest_articles=latest_articles,
        latest_messages=latest_messages)

@bp.route('/articles')
@login_required
@permission_required('article.view')
def article_list():
    page = request.args.get('page', 1, type=int)
    status = request.args.get('status', '', type=str)
    keyword = request.args.get('q', '', type=str).strip()
    query = Article.query
    if status:
        query = query.filter_by(status=status)
    if keyword:
        query = query.filter(
            Article.title.ilike(f'%{keyword}%'))
    pagination = query.order_by(
        Article.is_top.desc(),
        Article.created_at.desc()
    ).paginate(page=page, per_page=10, error_out=False)
    return render_template('admin/article_list.html',
        pagination=pagination, keyword=keyword,
        status=status)

@bp.route('/settings', methods=['GET', 'POST'])
@login_required
@permission_required('setting.view')
def settings():
    key_map = {item.key: item
               for item in SiteSetting.query.all()}
    form = SiteSettingForm(data={
        key: key_map.get(key).value
        if key in key_map else ''
        for key in SiteSettingForm()._fields
        if key != 'csrf_token'})
    if form.validate_on_submit():
        for key, field in form._fields.items():
            if key in {'csrf_token', 'submit'}:
                continue
            setting = key_map.get(key)
            if setting is None:
                setting = SiteSetting(
                    key=key, label=field.label.text,
                    group_name='general')
                db.session.add(setting)
            setting.value = field.data or ''
        db.session.commit()
        flash('站点设置已保存。', 'success')
        return redirect(url_for('admin.settings'))
    return render_template('admin/settings.html',
        form=form)
